/// # Shortcuts and Gestures
///
/// The following signals have default keybindings:
///
/// - `gtk.Paned.signals.accept_position`
/// - `gtk.Paned.signals.cancel_position`
/// - `gtk.Paned.signals.cycle_child_focus`
/// - `gtk.Paned.signals.cycle_handle_focus`
/// - `gtk.Paned.signals.move_handle`
/// - `gtk.Paned.signals.toggle_handle_focus`
///
/// # CSS nodes
///
/// ```
/// paned
/// ├── <child>
/// ├── separator[.wide]
/// ╰── <child>
/// ```
///
/// `GtkPaned` has a main CSS node with name paned, and a subnode for
/// the separator with name separator. The subnode gets a .wide style
/// class when the paned is supposed to be wide.
///
/// In horizontal orientation, the nodes are arranged based on the text
/// direction, so in left-to-right mode, :first-child will select the
/// leftmost child, while it will select the rightmost child in
/// RTL layouts.
///
/// ## Creating a paned widget with minimum sizes.
///
/// ```c
/// GtkWidget *hpaned = gtk_paned_new (GTK_ORIENTATION_HORIZONTAL);
/// GtkWidget *frame1 = gtk_frame_new (NULL);
/// GtkWidget *frame2 = gtk_frame_new (NULL);
///
/// gtk_widget_set_size_request (hpaned, 200, -1);
///
/// gtk_paned_set_start_child (GTK_PANED (hpaned), frame1);
/// gtk_paned_set_resize_start_child (GTK_PANED (hpaned), TRUE);
/// gtk_paned_set_shrink_start_child (GTK_PANED (hpaned), FALSE);
/// gtk_widget_set_size_request (frame1, 50, -1);
///
/// gtk_paned_set_end_child (GTK_PANED (hpaned), frame2);
/// gtk_paned_set_resize_end_child (GTK_PANED (hpaned), FALSE);
/// gtk_paned_set_shrink_end_child (GTK_PANED (hpaned), FALSE);
/// gtk_widget_set_size_request (frame2, 50, -1);
/// ```
pub const Paned = opaque {
    pub const Parent = gtk.Widget;
    pub const Implements = [_]type{ gtk.Accessible, gtk.AccessibleRange, gtk.Buildable, gtk.ConstraintTarget, gtk.Orientable };
    pub const Class = opaque {
