    pub const Parent = gtk.Widget;
    pub const Implements = [_]type{ gtk.Accessible, gtk.Buildable, gtk.ConstraintTarget, gtk.Native, gtk.ShortcutManager };
    pub const Class = gtk.PopoverClass;
    f_parent: gtk.Widget,

    pub const virtual_methods = struct {
