/// A print dialog for platforms which don’t provide a native
/// print dialog, like Unix.
///
/// <picture>
///   <source srcset="printdialog-dark.png" media="(prefers-color-scheme: dark)">
///   <img alt="An example GtkPrintUnixDialog" src="printdialog.png">
/// </picture>
///
/// It can be used very much like any other GTK dialog, at the cost of
/// the portability offered by the high-level printing API with
/// `gtk.PrintOperation`.
///
/// In order to print something with `GtkPrintUnixDialog`, you need to
/// use `gtk.PrintUnixDialog.getSelectedPrinter` to obtain a
/// `gtk.Printer` object and use it to construct a `gtk.PrintJob`
/// using `gtk.PrintJob.new`.
///
/// `GtkPrintUnixDialog` uses the following response values:
///
/// - `GTK_RESPONSE_OK`: for the “Print” button
/// - `GTK_RESPONSE_APPLY`: for the “Preview” button
/// - `GTK_RESPONSE_CANCEL`: for the “Cancel” button
///
/// # GtkPrintUnixDialog as GtkBuildable
///
/// The `GtkPrintUnixDialog` implementation of the `GtkBuildable` interface
/// exposes its `notebook` internal children with the name “notebook”.
///
/// An example of a `GtkPrintUnixDialog` UI definition fragment:
///
/// ```xml
/// <object class="GtkPrintUnixDialog" id="dialog1">
///   <child internal-child="notebook">
///     <object class="GtkNotebook" id="notebook">
///       <child>
///         <object type="GtkNotebookPage">
///           <property name="tab_expand">False</property>
///           <property name="tab_fill">False</property>
///           <property name="tab">
///             <object class="GtkLabel" id="tablabel">
///               <property name="label">Tab label</property>
///             </object>
///           </property>
///           <property name="child">
///             <object class="GtkLabel" id="tabcontent">
///               <property name="label">Content on notebook tab</property>
///             </object>
///           </property>
///         </object>
///       </child>
///     </object>
///   </child>
/// </object>
/// ```
///
/// # CSS nodes
///
/// `GtkPrintUnixDialog` has a single CSS node with name window. The style classes
/// dialog and print are added.
pub const PrintUnixDialog = opaque {
    pub const Parent = gtk.Dialog;
    pub const Implements = [_]type{ gtk.Accessible, gtk.Buildable, gtk.ConstraintTarget, gtk.Native, gtk.Root, gtk.ShortcutManager };
    pub const Class = opaque {
        pub const Instance = PrintUnixDialog;
    };
    pub const virtual_methods = struct {};

    pub const properties = struct {
        /// The current page in the document.
        pub const current_page = struct {
            pub const name = "current-page";

            pub const Type = c_int;
        };

        /// `TRUE` if the page setup controls are embedded.
        pub const embed_page_setup = struct {
            pub const name = "embed-page-setup";

            pub const Type = c_int;
        };

        /// Whether the application has a selection.
        pub const has_selection = struct {
            pub const name = "has-selection";

            pub const Type = c_int;
        };

        /// Capabilities the application can handle.
        pub const manual_capabilities = struct {
            pub const name = "manual-capabilities";

            pub const Type = gtk.PrintCapabilities;
        };

        /// The `GtkPageSetup` object to use.
        pub const page_setup = struct {
            pub const name = "page-setup";

            pub const Type = ?*gtk.PageSetup;
        };

        /// The `GtkPrintSettings` object used for this dialog.
        pub const print_settings = struct {
            pub const name = "print-settings";

            pub const Type = ?*gtk.PrintSettings;
        };

        /// The `GtkPrinter` which is selected.
        pub const selected_printer = struct {
            pub const name = "selected-printer";

            pub const Type = ?*gtk.Printer;
        };

        /// Whether the dialog supports selection.
        pub const support_selection = struct {
            pub const name = "support-selection";

            pub const Type = c_int;
        };
    };

    pub const signals = struct {};

    /// Creates a new `GtkPrintUnixDialog`.
    extern fn gtk_print_unix_dialog_new(p_title: ?[*:0]const u8, p_parent: ?*gtk.Window) *gtk.PrintUnixDialog;
    pub const new = gtk_print_unix_dialog_new;

    /// Adds a custom tab to the print dialog.
    extern fn gtk_print_unix_dialog_add_custom_tab(p_dialog: *PrintUnixDialog, p_child: *gtk.Widget, p_tab_label: *gtk.Widget) void;
    pub const addCustomTab = gtk_print_unix_dialog_add_custom_tab;

    /// Gets the current page of the `GtkPrintUnixDialog`.
    extern fn gtk_print_unix_dialog_get_current_page(p_dialog: *PrintUnixDialog) c_int;
    pub const getCurrentPage = gtk_print_unix_dialog_get_current_page;

    /// Gets whether to embed the page setup.
    extern fn gtk_print_unix_dialog_get_embed_page_setup(p_dialog: *PrintUnixDialog) c_int;
    pub const getEmbedPageSetup = gtk_print_unix_dialog_get_embed_page_setup;

    /// Gets whether there is a selection.
    extern fn gtk_print_unix_dialog_get_has_selection(p_dialog: *PrintUnixDialog) c_int;
    pub const getHasSelection = gtk_print_unix_dialog_get_has_selection;

    /// Gets the capabilities that have been set on this `GtkPrintUnixDialog`.
    extern fn gtk_print_unix_dialog_get_manual_capabilities(p_dialog: *PrintUnixDialog) gtk.PrintCapabilities;
    pub const getManualCapabilities = gtk_print_unix_dialog_get_manual_capabilities;

    /// Gets the page setup that is used by the `GtkPrintUnixDialog`.
    extern fn gtk_print_unix_dialog_get_page_setup(p_dialog: *PrintUnixDialog) *gtk.PageSetup;
    pub const getPageSetup = gtk_print_unix_dialog_get_page_setup;

    /// Gets whether a page setup was set by the user.
    extern fn gtk_print_unix_dialog_get_page_setup_set(p_dialog: *PrintUnixDialog) c_int;
    pub const getPageSetupSet = gtk_print_unix_dialog_get_page_setup_set;

    /// Gets the currently selected printer.
    extern fn gtk_print_unix_dialog_get_selected_printer(p_dialog: *PrintUnixDialog) ?*gtk.Printer;
    pub const getSelectedPrinter = gtk_print_unix_dialog_get_selected_printer;

    /// Gets a new `GtkPrintSettings` object that represents the
    /// current values in the print dialog.
    ///
    /// Note that this creates a new object, and you need to unref
    /// it if don’t want to keep it.
    extern fn gtk_print_unix_dialog_get_settings(p_dialog: *PrintUnixDialog) *gtk.PrintSettings;
    pub const getSettings = gtk_print_unix_dialog_get_settings;

    /// Gets whether the print dialog allows user to print a selection.
    extern fn gtk_print_unix_dialog_get_support_selection(p_dialog: *PrintUnixDialog) c_int;
    pub const getSupportSelection = gtk_print_unix_dialog_get_support_selection;

    /// Sets the current page number.
    ///
    /// If `current_page` is not -1, this enables the current page choice
    /// for the range of pages to print.
    extern fn gtk_print_unix_dialog_set_current_page(p_dialog: *PrintUnixDialog, p_current_page: c_int) void;
    pub const setCurrentPage = gtk_print_unix_dialog_set_current_page;

    /// Embed page size combo box and orientation combo box into page setup page.
    extern fn gtk_print_unix_dialog_set_embed_page_setup(p_dialog: *PrintUnixDialog, p_embed: c_int) void;
    pub const setEmbedPageSetup = gtk_print_unix_dialog_set_embed_page_setup;

    /// Sets whether a selection exists.
    extern fn gtk_print_unix_dialog_set_has_selection(p_dialog: *PrintUnixDialog, p_has_selection: c_int) void;
    pub const setHasSelection = gtk_print_unix_dialog_set_has_selection;

    /// This lets you specify the printing capabilities your application
    /// supports.
    ///
    /// For instance, if you can handle scaling the output then you pass
    /// `GTK_PRINT_CAPABILITY_SCALE`. If you don’t pass that, then the dialog
    /// will only let you select the scale if the printing system automatically
    /// handles scaling.
    extern fn gtk_print_unix_dialog_set_manual_capabilities(p_dialog: *PrintUnixDialog, p_capabilities: gtk.PrintCapabilities) void;
    pub const setManualCapabilities = gtk_print_unix_dialog_set_manual_capabilities;

    /// Sets the page setup of the `GtkPrintUnixDialog`.
    extern fn gtk_print_unix_dialog_set_page_setup(p_dialog: *PrintUnixDialog, p_page_setup: *gtk.PageSetup) void;
    pub const setPageSetup = gtk_print_unix_dialog_set_page_setup;

    /// Sets the `GtkPrintSettings` for the `GtkPrintUnixDialog`.
    ///
    /// Typically, this is used to restore saved print settings
    /// from a previous print operation before the print dialog
    /// is shown.
    extern fn gtk_print_unix_dialog_set_settings(p_dialog: *PrintUnixDialog, p_settings: ?*gtk.PrintSettings) void;
    pub const setSettings = gtk_print_unix_dialog_set_settings;

    /// Sets whether the print dialog allows user to print a selection.
    extern fn gtk_print_unix_dialog_set_support_selection(p_dialog: *PrintUnixDialog, p_support_selection: c_int) void;
    pub const setSupportSelection = gtk_print_unix_dialog_set_support_selection;

    extern fn gtk_print_unix_dialog_get_type() usize;
    pub const getGObjectType = gtk_print_unix_dialog_get_type;

    extern fn g_object_ref(p_self: *gtk.PrintUnixDialog) void;
    pub const ref = g_object_ref;

    extern fn g_object_unref(p_self: *gtk.PrintUnixDialog) void;
    pub const unref = g_object_unref;

    pub fn as(p_instance: *PrintUnixDialog, comptime P_T: type) *P_T {
        return gobject.ext.as(P_T, p_instance);
    }

    test {
        @setEvalBranchQuota(100_000);
        std.testing.refAllDecls(@This());
    }
};

/// Represents a printer.
///
/// You only need to deal directly with printers if you use the
/// non-portable `gtk.PrintUnixDialog` API.
///
/// A `GtkPrinter` allows to get status information about the printer,
/// such as its description, its location, the number of queued jobs,
/// etc. Most importantly, a `GtkPrinter` object can be used to create
/// a `gtk.PrintJob` object, which lets you print to the printer.
pub const Printer = opaque {
    pub const Parent = gobject.Object;
    pub const Implements = [_]type{};
    pub const Class = opaque {
        pub const Instance = Printer;
    };
    pub const virtual_methods = struct {};

    pub const properties = struct {
        /// `TRUE` if the printer is accepting jobs.
        pub const accepting_jobs = struct {
            pub const name = "accepting-jobs";

            pub const Type = c_int;
        };

        /// `TRUE` if this printer can accept PDF.
        pub const accepts_pdf = struct {
            pub const name = "accepts-pdf";

            pub const Type = c_int;
        };

        /// `TRUE` if this printer can accept PostScript.
        pub const accepts_ps = struct {
            pub const name = "accepts-ps";

            pub const Type = c_int;
        };

        /// The backend for the printer.
        pub const backend = struct {
            pub const name = "backend";

            pub const Type = @compileError("no type information available");
        };

        /// Icon name to use for the printer.
        pub const icon_name = struct {
            pub const name = "icon-name";

            pub const Type = ?[*:0]u8;
        };

        /// `FALSE` if this represents a real hardware device.
        pub const is_virtual = struct {
            pub const name = "is-virtual";

            pub const Type = c_int;
        };

        /// Number of jobs queued in the printer.
        pub const job_count = struct {
            pub const name = "job-count";

            pub const Type = c_int;
        };

        /// Information about the location of the printer.
        pub const location = struct {
            pub const name = "location";

            pub const Type = ?[*:0]u8;
        };

        /// The name of the printer.
        pub const name = struct {
            pub const name = "name";

            pub const Type = ?[*:0]u8;
        };

        /// `TRUE` if this printer is paused.
        ///
        /// A paused printer still accepts jobs, but it does
        /// not print them.
        pub const paused = struct {
            pub const name = "paused";

            pub const Type = c_int;
        };

        /// String giving the current status of the printer.
        pub const state_message = struct {
            pub const name = "state-message";

            pub const Type = ?[*:0]u8;
        };
    };

    pub const signals = struct {
        /// Emitted in response to a request for detailed information
        /// about a printer from the print backend.
        ///
        /// The `success` parameter indicates if the information was
        /// actually obtained.
        pub const details_acquired = struct {
            pub const name = "details-acquired";

            pub fn connect(p_instance: anytype, comptime P_Data: type, p_callback: *const fn (@TypeOf(p_instance), p_success: c_int, P_Data) callconv(.c) void, p_data: P_Data, p_options: gobject.ext.ConnectSignalOptions(P_Data)) c_ulong {
                return gobject.signalConnectClosureById(
                    @ptrCast(@alignCast(gobject.ext.as(Printer, p_instance))),
                    gobject.signalLookup("details-acquired", Printer.getGObjectType()),
                    glib.quarkFromString(p_options.detail orelse null),
                    gobject.CClosure.new(@ptrCast(p_callback), p_data, @ptrCast(p_options.destroyData)),
                    @intFromBool(p_options.after),
                );
            }
        };
    };

    /// Creates a new `GtkPrinter`.
    extern fn gtk_printer_new(p_name: [*:0]const u8, p_backend: *gtk.PrintBackend, p_virtual_: c_int) *gtk.Printer;
    pub const new = gtk_printer_new;

    /// Returns whether the printer accepts input in
