    extern fn gtk_printer_accepts_pdf(p_printer: *Printer) c_int;
    pub const acceptsPdf = gtk_printer_accepts_pdf;

    /// Returns whether the printer accepts input in
    /// PostScript format.
    extern fn gtk_printer_accepts_ps(p_printer: *Printer) c_int;
    pub const acceptsPs = gtk_printer_accepts_ps;

    /// Compares two printers.
    extern fn gtk_printer_compare(p_a: *Printer, p_b: *gtk.Printer) c_int;
