        /// The child widget.
        pub const child = struct {
            pub const name = "child";

            pub const Type = ?*gtk.Widget;
        };

        /// The key capture widget.
        pub const key_capture_widget = struct {
            pub const name = "key-capture-widget";

            pub const Type = ?*gtk.Widget;
        };

        /// Whether the search mode is on and the search bar shown.
        pub const search_mode_enabled = struct {
            pub const name = "search-mode-enabled";

            pub const Type = c_int;
        };

        /// Whether to show the close button in the search bar.
        pub const show_close_button = struct {
            pub const name = "show-close-button";

            pub const Type = c_int;
        };
    };

    pub const signals = struct {};

    /// Creates a `GtkSearchBar`.
    ///
    /// You will need to tell it about which widget is going to be your text
    /// entry using `gtk.SearchBar.connectEntry`.
