    pub const getChild = gtk_search_bar_get_child;

    /// Gets the widget that `bar` is capturing key events from.
    extern fn gtk_search_bar_get_key_capture_widget(p_bar: *SearchBar) ?*gtk.Widget;
    pub const getKeyCaptureWidget = gtk_search_bar_get_key_capture_widget;

    /// Returns whether the search mode is on or off.
    extern fn gtk_search_bar_get_search_mode(p_bar: *SearchBar) c_int;
    pub const getSearchMode = gtk_search_bar_get_search_mode;

