/// Shows window frame controls.
///
/// Typical window frame controls are minimize, maximize and close buttons,
/// and the window icon.
///
/// <picture>
///   <source srcset="windowcontrols-dark.png" media="(prefers-color-scheme: dark)">
///   <img alt="An example GtkWindowControls" src="windowcontrols.png">
/// </picture>
///
/// `GtkWindowControls` only displays start or end side of the controls (see
/// `gtk.WindowControls.properties.side`), so it's intended to be always used
/// in pair with another `GtkWindowControls` for the opposite side, for example:
///
/// ```xml
/// <object class="GtkBox">
///   <child>
///     <object class="GtkWindowControls">
///       <property name="side">start</property>
///     </object>
///   </child>
///
///   ...
///
///   <child>
///     <object class="GtkWindowControls">
///       <property name="side">end</property>
///     </object>
///   </child>
/// </object>
/// ```
///
/// # CSS nodes
///
/// ```
/// windowcontrols
/// ├── [image.icon]
/// ├── [button.minimize]
/// ├── [button.maximize]
/// ╰── [button.close]
/// ```
///
/// A `GtkWindowControls`' CSS node is called windowcontrols. It contains
/// subnodes corresponding to each title button. Which of the title buttons
/// exist and where they are placed exactly depends on the desktop environment
/// and `gtk.WindowControls.properties.decoration_layout` value.
///
/// When `gtk.WindowControls.properties.empty` is true, it gets the .empty
/// style class.
///
/// # Accessibility
///
/// `GtkWindowControls` uses the `gtk.@"AccessibleRole.group"` role.
pub const WindowControls = opaque {
    pub const Parent = gtk.Widget;
    pub const Implements = [_]type{ gtk.Accessible, gtk.Buildable, gtk.ConstraintTarget };
    pub const Class = gtk.WindowControlsClass;
    pub const virtual_methods = struct {};

    pub const properties = struct {
        /// The decoration layout for window buttons.
        ///
        /// If this property is not set, the
        /// `gtk.Settings.properties.gtk_decoration_layout` setting is used.
        pub const decoration_layout = struct {
            pub const name = "decoration-layout";

            pub const Type = ?[*:0]u8;
        };

        /// Whether the widget has any window buttons.
        pub const empty = struct {
            pub const name = "empty";

            pub const Type = c_int;
        };

        /// Whether the widget shows start or end side of the decoration layout.
        ///
        /// See `gtk.WindowControls.properties.decoration_layout`.
        pub const side = struct {
            pub const name = "side";

            pub const Type = gtk.PackType;
        };

        /// Whether to show platform native close/minimize/maximize buttons.
        ///
        /// For macOS, the `gtk.HeaderBar.properties.decoration_layout` property
        /// controls the use of native window controls.
        ///
        /// On other platforms, this option has no effect.
        ///
        /// See also [Using GTK on Apple macOS](osx.html?native-window-controls).
        pub const use_native_controls = struct {
            pub const name = "use-native-controls";

            pub const Type = c_int;
        };
    };

    pub const signals = struct {};

    /// Creates a new `GtkWindowControls`.
    extern fn gtk_window_controls_new(p_side: gtk.PackType) *gtk.WindowControls;
    pub const new = gtk_window_controls_new;

    /// Gets the decoration layout of this window controls widget
    extern fn gtk_window_controls_get_decoration_layout(p_self: *WindowControls) ?[*:0]const u8;
    pub const getDecorationLayout = gtk_window_controls_get_decoration_layout;

    /// Gets whether the widget has any window buttons.
    extern fn gtk_window_controls_get_empty(p_self: *WindowControls) c_int;
    pub const getEmpty = gtk_window_controls_get_empty;

    /// Gets the side to which this window controls widget belongs.
    extern fn gtk_window_controls_get_side(p_self: *WindowControls) gtk.PackType;
    pub const getSide = gtk_window_controls_get_side;

    /// Returns whether platform native window controls are shown.
    extern fn gtk_window_controls_get_use_native_controls(p_self: *WindowControls) c_int;
    pub const getUseNativeControls = gtk_window_controls_get_use_native_controls;

    /// Sets the decoration layout for the title buttons.
    ///
    /// This overrides the `gtk.Settings.properties.gtk_decoration_layout`
    /// setting.
    ///
    /// The format of the string is button names, separated by commas.
    /// A colon separates the buttons that should appear on the left
    /// from those on the right. Recognized button names are minimize,
    /// maximize, close and icon (the window icon).
