///
/// In GTK, the main objects that implement this interface are
/// `gtk.FileChooserWidget` and `gtk.FileChooserDialog`.
///
/// You do not need to write an object that implements the `GtkFileChooser`
/// interface unless you are trying to adapt an existing file selector to
/// expose a standard programming interface.
///
/// `GtkFileChooser` allows for shortcuts to various places in the filesystem.
/// In the default implementation these are displayed in the left pane. It
/// may be a bit confusing at first that these shortcuts come from various
/// sources and in various flavours, so lets explain the terminology here:
///
/// - Bookmarks: are created by the user, by dragging folders from the
///   right pane to the left pane, or by using the “Add”. Bookmarks
///   can be renamed and deleted by the user.
///
/// - Shortcuts: can be provided by the application. For example, a Paint
///   program may want to add a shortcut for a Clipart folder. Shortcuts
///   cannot be modified by the user.
///
/// - Volumes: are provided by the underlying filesystem abstraction. They are
///   the “roots” of the filesystem.
///
/// # File Names and Encodings
///
/// When the user is finished selecting files in a `GtkFileChooser`, your
/// program can get the selected filenames as `GFile`s.
///
/// # Adding options
///
/// You can add extra widgets to a file chooser to provide options
/// that are not present in the default design, by using
/// `gtk.FileChooser.addChoice`. Each choice has an identifier and
/// a user visible label; additionally, each choice can have multiple
/// options. If a choice has no option, it will be rendered as a
/// check button with the given label; if a choice has options, it will
/// be rendered as a combo box.
pub const FileChooser = opaque {
    pub const Prerequisites = [_]type{gobject.Object};
    pub const Iface = opaque {
        pub const Instance = FileChooser;
    };
    pub const virtual_methods = struct {};

    pub const properties = struct {
        /// The type of operation that the file chooser is performing.
        pub const action = struct {
            pub const name = "action";

            pub const Type = gtk.FileChooserAction;
        };

        /// Whether a file chooser not in `GTK_FILE_CHOOSER_ACTION_OPEN` mode
        /// will offer the user to create new folders.
        pub const create_folders = struct {
            pub const name = "create-folders";

            pub const Type = c_int;
        };

        /// The current filter for selecting files that are displayed.
        pub const filter = struct {
            pub const name = "filter";

            pub const Type = ?*gtk.FileFilter;
        };

        /// A `GListModel` containing the filters that have been
        /// added with `gtk.FileChooser.addFilter`.
        ///
        /// The returned object should not be modified. It may
        /// or may not be updated for later changes.
        pub const filters = struct {
            pub const name = "filters";

            pub const Type = ?*gio.ListModel;
        };

        /// Whether to allow multiple files to be selected.
        pub const select_multiple = struct {
            pub const name = "select-multiple";

            pub const Type = c_int;
        };

        /// A `GListModel` containing the shortcut folders that have been
        /// added with `gtk.FileChooser.addShortcutFolder`.
        ///
        /// The returned object should not be modified. It may
        /// or may not be updated for later changes.
        pub const shortcut_folders = struct {
            pub const name = "shortcut-folders";

            pub const Type = ?*gio.ListModel;
        };
    };

    pub const signals = struct {};

    /// Adds a 'choice' to the file chooser.
    ///
    /// This is typically implemented as a combobox or, for boolean choices,
    /// as a checkbutton. You can select a value using
    /// `gtk.FileChooser.setChoice` before the dialog is shown,
    /// and you can obtain the user-selected value in the
    /// `gtk.Dialog.signals.response` signal handler using
    /// `gtk.FileChooser.getChoice`.
    extern fn gtk_file_chooser_add_choice(p_chooser: *FileChooser, p_id: [*:0]const u8, p_label: [*:0]const u8, p_options: ?[*][*:0]const u8, p_option_labels: ?[*][*:0]const u8) void;
    pub const addChoice = gtk_file_chooser_add_choice;

    /// Adds `filter` to the list of filters that the user can select between.
    ///
    /// When a filter is selected, only files that are passed by that
    /// filter are displayed.
    ///
