        /// range from n_items to G_MAXUINT will be returned.
        pub const get_section = struct {
            pub fn call(p_class: anytype, p_self: *@typeInfo(@TypeOf(p_class)).pointer.child.Instance, p_position: c_uint, p_out_start: *c_uint, p_out_end: *c_uint) void {
                return gobject.ext.as(SectionModel.Iface, p_class).f_get_section.?(gobject.ext.as(SectionModel, p_self), p_position, p_out_start, p_out_end);
