                gobject.ext.as(SectionModel.Iface, p_class).f_get_section = @ptrCast(p_implementation);
            }
        };
    };

    pub const properties = struct {};

    pub const signals = struct {
        /// Emitted when the start-of-section state of some of the items in `model` changes.
        ///
        /// Note that this signal does not specify the new section state of the
        /// items, they need to be queried manually. It is also not necessary for
        /// a model to change the section state of any of the items in the section
        /// model, though it would be rather useless to emit such a signal.
        ///
        /// The `gio.ListModel.signals.items_changed` implies the effect of the
        /// `gtk.SectionModel.signals.sections_changed` signal for all the items
        /// it covers.
        pub const sections_changed = struct {
            pub const name = "sections-changed";

            pub fn connect(p_instance: anytype, comptime P_Data: type, p_callback: *const fn (@TypeOf(p_instance), p_position: c_uint, p_n_items: c_uint, P_Data) callconv(.c) void, p_data: P_Data, p_options: gobject.ext.ConnectSignalOptions(P_Data)) c_ulong {
                return gobject.signalConnectClosureById(
